// // This module calculates the absolute value of a signed 32-bit input. If the input is positive, it outputs the negation of the input; otherwise, it simply outputs the input as is.
module top_module(
  input signed [31:0] in,
  output reg [31:0] out
);always @(*) begin
    if (in < 0) begin
      out = -in;
    end
    else begin
      out = in;
    end
  end

endmodule
